// Split leaderboard into individual wallet entries
const leaderboard = $input.first().json;
const entries = Array.isArray(leaderboard) ? leaderboard : [leaderboard];
return entries.map(entry => ({ json: { proxyWallet: entry.proxyWallet, rank: entry.rank, userName: entry.userName || entry.proxyWallet } }));

// Collect all positions and tag with wallet info
const allPositions = [];

for (const item of $input.all()) {
  const positions = Array.isArray(item.json) ? item.json : [item.json];
  for (const pos of positions) {
    if (pos.conditionId && pos.outcome) {
      allPositions.push({
        json: {
          conditionId: pos.conditionId,
          outcome: pos.outcome,
          proxyWallet: pos.user || pos.proxyWallet,
          size: parseFloat(pos.size || '0'),
          tokenId: pos.tokenId || pos.assetId || ''
        }
      });
    }
  }
}

return allPositions.length > 0 ? allPositions : [];

// Group positions by market + side and find consensus (3+ wallets)
const groups = {};

for (const item of $input.all()) {
  const pos = item.json;
  const key = `${pos.conditionId}_${pos.outcome}`;
  if (!groups[key]) {
    groups[key] = {
      conditionId: pos.conditionId,
      outcome: pos.outcome,
      tokenId: pos.tokenId,
      wallets: new Set(),
      totalSize: 0
    };
  }
  groups[key].wallets.add(pos.proxyWallet);
  groups[key].totalSize += pos.size;
}

// Filter for 3+ wallets on same side
const consensus = Object.values(groups)
  .filter(g => g.wallets.size >= 3)
  .map(g => ({
    json: {
      conditionId: g.conditionId,
      outcome: g.outcome,
      tokenId: g.tokenId,
      count: g.wallets.size,
      wallets: [...g.wallets],
      totalSize: g.totalSize
    }
  }));

if (consensus.length === 0) {
  return [];
}

return consensus;

// Merge market API response with original consensus data from earlier node.
// The HTTP Request node overwrites item.json with the API response,
// so we recover consensus data by referencing the prior Code node's output.
// Key by conditionId to avoid index misalignment if HTTP requests reorder.
const consensusMap = {};
for (const c of $('Find Consensus (3+ Wallets)').all()) {
  consensusMap[c.json.conditionId] = c.json;
}
const items = $input.all();
return items.map(item => {
  const consensus = consensusMap[item.json.conditionId || item.json.condition_id] || {};
  return { json: { ...item.json, _consensus: consensus } };
});

// Format consensus alerts with market details
const WEBHOOK_URL = $env.WEBHOOK_URL || 'http://localhost:3000';

const results = [];

for (const item of $input.all()) {
  const market = item.json;
  const consensus = item.json._consensus || {};

  const outcomePrices = JSON.parse(market.outcomePrices || '[0, 0]');
  const clobTokenIds = JSON.parse(market.clobTokenIds || '["", ""]');
  const currentPrice = parseFloat(outcomePrices[0]) || 0;
  const tokenId = clobTokenIds[0] || consensus.tokenId || '';
  const count = consensus.count || 0;
  const outcome = consensus.outcome || 'YES';

  results.push({
    json: {
      webhookUrl: WEBHOOK_URL + '/api/alert',
      payload: {
        category: 'smart_money',
        title: `Smart money consensus: ${count} of top 10 traders hold ${outcome} on "${market.question}"`,
        body: `${count} of the top 10 Polymarket traders by all-time P&L hold ${outcome} positions on "${market.question}". Current price: $${currentPrice.toFixed(2)}. Combined position size: $${Math.round(consensus.totalSize || 0).toLocaleString()}.`,
        market: {
          conditionId: market.conditionId || consensus.conditionId,
          question: market.question || 'Unknown market',
          tokenId: tokenId,
          currentPrice: currentPrice
        },
        urgent: false,
        metadata: {
          consensusCount: count,
          outcome: outcome,
          wallets: consensus.wallets || [],
          totalSize: consensus.totalSize || 0
        }
      }
    }
  });
}

if (results.length === 0) {
  return [];
}

return results;
